// Get the text output from the AI agent
const agentOutput = items[0].json.output;
let jsonString = agentOutput;

// --- NEW BLOCK: JSON CLEANUP & EXTRACTION ---
// Find the start index of '[' and the end index of ']'
const startIndex = jsonString.indexOf('[');
const endIndex = jsonString.lastIndexOf(']');

// If both start and end are found, extract the clean JSON
if (startIndex !== -1 && endIndex !== -1) {
  jsonString = jsonString.substring(startIndex, endIndex + 1);
}
// --- END OF NEW BLOCK ---

try {
  // Parse the cleaned text string into a real JSON object
  const parsedPlan = JSON.parse(jsonString);

  // Return the task array for further processing
  return parsedPlan;
} catch (error) {
  // If parsing still fails after cleanup, return the error for diagnostics
  return { error: "Failed to parse JSON", details: error.message, originalOutput: agentOutput };
}
